#include <bits/stdc++.h>
#define int long long
#define ull unsigned long long
#define mk make_pair
#define PII pair<int,int>
#define NoAns puts("-1");
#define FOR(i,j,k) for(int i=(j);i<=(k);++i)
#define ROF(i,j,k) for(int i=(j);i>=(k);--i)
#define FOI(a,b) for(auto a : b)
#define Yes puts("Yes");
#define No puts("No");
#define llinf 0x3f3f3f3f3f3f3f3f
#define inf 0x3f3f3f3f
#define ll long long
#define snd second
#define fst first
#define il inline
#define pb push_back
#define CI const int
#define cl(x) memset(x,0,sizeof x)
#define cli(x) memset(x,0x3f,sizeof x)
#define lowbit(x) (x&(-x))
#define wh while
#define gc() getchar()
#define pc(x) putchar(x)
#define NP namespace
#define ls (k<<1)
#define rs (k<<1|1)
#define mid ((l+r)>>1)
using NP std;
NP phigrOS
{
    il ll read()
    {
        ll x=0,f=1;char ch=gc();
        wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
        wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
        return x*f;
    }
    void write(ll x)
    {
        if(x<0)pc('-'),x=-x;
        if(x>9)write(x/10);
        pc(x%10+'0');
    }
    void writeln(ll x)
    {
        write(x);
        puts("");
        return;
    }
}
using NP phigrOS;
CI MAXN=1e5+5;
int dis[MAXN][2],n,m,st[MAXN][2];
vector<PII> g[MAXN];
void dijkstra(int s)
{
    priority_queue<PII,vector<PII>,greater<>> q;
    cli(dis);
    cl(st);
    dis[s][0]=0;
    q.push(mk(0,s));
    wh(q.size())
    {
        PII t=q.top();q.pop();
        int dd=t.fst,u=t.snd,k;
        if(dd>dis[u][1])continue;
        if(dd==dis[u][0])k=0;
        else k=1;
        if(st[u][k])continue;
        st[u][k]=1;
        FOI(e,g[u])
        {
            int x=e.fst,w=e.snd,nw=dd+w;
            if(nw<dis[x][0])
            {
                dis[x][1]=dis[x][0];
                q.push(mk(dis[x][1],x));
                dis[x][0]=nw;
                q.push(mk(dis[x][0],x));
            }
            else if(nw>dis[x][0]&&nw<dis[x][1])
            {
                dis[x][1]=nw;
                q.push(mk(dis[x][1],x));
            }
        }
    }
}
signed main(void)
{
    n=read(),m=read();
    FOR(i,1,m)
    {
        int u=read(),v=read(),w=read();
        g[u].pb(mk(v,w));
        g[v].pb(mk(u,w));
    }
    dijkstra(1);
    write(dis[n][1]);
    return false;
}
